import core.int
import core.array

const MOD: Int64 = 1_000_000_007

fn digit_sum(n: Int64): Int64 {
    var sum: Int64 = 0
    var num = n
    if num < 0 { num = -num } // Should not happen given constraints
    while num > 0 {
        sum += num % 10
        num /= 10
    }
    return sum
}

fn solve(digitSum: Array(Int64)): Int64 {
    let max_allowed_value: Int64 = 5000
    // Since max digit sum for 5000 is 5 (for 5000) or 31 (for 4999), we only need up to 50.
    let max_D: Int = 50 

    // V[D] stores a sorted list of numbers x in [0, 5000] such that digit_sum(x) == D.
    var V: Array(Array(Int64)) = Array.new(max_D + 1) { [] }

    // Step 1: Precalculate valid numbers V[D]
    for d in 0..max_D {
        V[d] = []
    }

    for x in 0..max_allowed_value {
        let d_sum = digit_sum(x)
        if d_sum <= max_D {
            V[d_sum].push(x)
        }
    }

    let N = digitSum.len

    // DP state: We only need the previous row.
    // DP_prev[j] = count of valid sequences ending at V[D_prev][j]
    var DP_prev: Array(Int64) = []

    // Base Case: i = 0 (First element)
    let D0 = digitSum[0]
    let V0 = V[D0]
    if V0.len == 0 {
        return 0
    }
    DP_prev = Array.new(V0.len) { 1 }

    // DP Transition: i = 1 to N-1
    for i in 1..<N {
        let Di = digitSum[i]
        let Vi = V[Di]
        let V_prev = V[digitSum[i-1]]

        if Vi.len == 0 {
            return 0 // No valid number for Di
        }

        let DP_curr: Array(Int64) = Array.new(Vi.len) { 0 }

        // Calculate prefix sums for the previous DP layer (DP_prev)
        // S_prev[k] = sum(DP_prev[0] ... DP_prev[k-1])
        // S_prev size is |V_prev| + 1
        var S_prev: Array(Int64) = Array.new(V_prev.len + 1) { 0 }
        for k in 0..<V_prev.len {
            S_prev[k + 1] = (S_prev[k] + DP_prev[k]) % MOD
        }

        // Iterate through current choices (a_i = Vi[j])
        for j in 0..<Vi.len {
            let current_val = Vi[j]

            // Find the number of elements in V_prev that are <= current_val.
            // Since V_prev is sorted, we find the index k_max such that V_prev[k_max] <= current_val.
            // We use binary search (or similar logic) to find the count.

            // Find insertion point: index of the first element strictly greater than current_val.
            var low = 0
            var high = V_prev.len
            var count_le: Int = 0

            while low < high {
                let mid = low + (high - low) / 2
                if V_prev[mid] <= current_val {
                    low = mid + 1
                } else {
                    high = mid
                }
            }

            // 'low' is now the count of elements <= current_val (if 0-indexed, it's the exclusive upper bound).
            count_le = low

            // The sum we need is S_prev[count_le]
            if count_le > 0 {
                DP_curr[j] = S_prev[count_le]
            } else {
                // If count_le is 0, no preceding element is less than or equal, so DP_curr[j] = 0.
                DP_curr[j] = 0
            }
        }

        DP_prev = DP_curr
    }

    // Final Result: Sum up all counts in the last DP row
    var total_count: Int64 = 0
    for count in DP_prev {
        total_count = (total_count + count) % MOD
    }

    return total_count
}
