import std::math
import std::array
import std::int

const MOD = 1_000_000_007

fn sum_digits(n: Int64): Int {
    var sum = 0
    var current = n
    while current > 0 {
        sum += (current % 10)
        current /= 10
    }
    return sum
}

fn solve(digitSum : Array(Int64)) : Int64 {
    let N = digitSum.len
    let MAX_V = 5000
    let MAX_S = 50 // Max digitSum is 50

    // Step 1: Precompute V[S] - list of all numbers v in [0, 5000] with sum of digits S.
    var V: Array[Vector[Int64]] = Array[Vector[Int64]].new(MAX_S + 1)
    for s in 0..MAX_S {
        V[s] = Vector[Int64].new()
    }

    for v in 0..MAX_V {
        let s = sum_digits(v as Int64)
        if s <= MAX_S {
            V[s].push(v as Int64)
        }
    }

    // Step 2: Dynamic Programming
    // DP_prev[v] stores the count of valid sequences ending at value v at step i-1.
    var dp_prev: Array[Int64] = Array[Int64].new(MAX_V + 1)
    // dp_curr[v] stores the count of valid sequences ending at value v at step i.
    var dp_curr: Array[Int64] = Array[Int64].new(MAX_V + 1)

    for i in 0..<N {
        let current_s = digitSum[i]
        let P_i = V[current_s]

        // Reset current DP state
        for v in 0..MAX_V {
            dp_curr[v] = 0
        }

        if i == 0 {
            // Base Case (i=0)
            for v in P_i {
                dp_curr[v as Int] = 1
            }
        } else {
            // Transition (i > 0)

            // 1. Calculate prefix sums of dp_prev
            var prefix_sum_prev: Array[Int64] = Array[Int64].new(MAX_V + 1)
            var current_sum: Int64 = 0
            for v in 0..MAX_V {
                current_sum = (current_sum + dp_prev[v]) % MOD
                prefix_sum_prev[v] = current_sum
            }

            // 2. Calculate dp_curr[v] for v in P_i
            for v in P_i {
                // dp_curr[v] = Sum(dp_prev[u] for u <= v)
                // This is exactly prefix_sum_prev[v]
                let count = prefix_sum_prev[v as Int]
                dp_curr[v as Int] = count
            }
        }

        // Swap DP states for the next iteration
        dp_prev = dp_curr
        dp_curr = Array[Int64].new(MAX_V + 1) // Reinitialize dp_curr for next round
    }

    // Step 3: Final Answer
    let last_s = digitSum[N - 1]
    let P_last = V[last_s]

    var total_count: Int64 = 0
    for v in P_last {
        total_count = (total_count + dp_prev[v as Int]) % MOD
    }

    return total_count
}
